insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('spanish:3-1-school-life-and-subjects:tf:18d22ce1', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "‘El aula’ means ‘the hall’, not ‘the classroom’."}'::jsonb, '{"answer": false, "explain": "el aula = the classroom. ‘the hall’ would be el pasillo or el salón de actos."}'::jsonb),
('spanish:3-1-school-life-and-subjects:tf:3f64a375', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "Comparatives use ‘más + adjective + que’ to say ‘more … than’."}'::jsonb, '{"answer": true, "explain": "más difícil que = more difficult than."}'::jsonb),
('spanish:3-1-school-life-and-subjects:tf:068aee43', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "‘El recreo’ is when students can go outside to the patio."}'::jsonb, '{"answer": true, "explain": "el recreo = break time, often spent in el patio."}'::jsonb),
('spanish:3-1-school-life-and-subjects:tf:f559e80c', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "‘La escuela’ usually means a secondary school for teenagers."}'::jsonb, '{"answer": false, "explain": "False! la escuela usually means a primary school; el instituto is secondary school."}'::jsonb),
('spanish:3-1-school-life-and-subjects:tf:3ef2368e', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "‘Suspender un examen’ means to fail it."}'::jsonb, '{"answer": true, "explain": "suspender = to fail (a false-friend trap, since it looks like the English ‘suspend’)."}'::jsonb),
('spanish:3-1-school-life-and-subjects:tf:b50a2a6b', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "‘Vago’ and ‘perezoso’ both mean ‘lazy’."}'::jsonb, '{"answer": true, "explain": "Both vago and perezoso describe a lazy student."}'::jsonb),
('spanish:3-1-school-life-and-subjects:tf:4fdffa12', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "‘El acoso’ means friendly teasing that is harmless."}'::jsonb, '{"answer": false, "explain": "False! el acoso = bullying, a serious problem, not harmless teasing."}'::jsonb),
('spanish:3-1-school-life-and-subjects:tf:b3eb07f1', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "September (‘septiembre’) is when the Spanish school year usually begins."}'::jsonb, '{"answer": true, "explain": "septiembre = September, the start of the school year."}'::jsonb),
('spanish:3-1-school-life-and-subjects:tf:44e49a50', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "‘Estricto’ means relaxed and easy-going."}'::jsonb, '{"answer": false, "explain": "False! estricto means strict, the opposite of relaxed."}'::jsonb),
('spanish:3-1-school-life-and-subjects:tf:cced5c24', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "‘Preocuparse por’ means ‘to worry about’."}'::jsonb, '{"answer": true, "explain": "preocuparse por = to worry about (something)."}'::jsonb),
('spanish:3-1-school-life-and-subjects:tf:d16e7656', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'tf', 'tf', 1, '{"question": "‘Advertir’ means ‘to advertise a product’."}'::jsonb, '{"answer": false, "explain": "False friend trap! advertir = to warn, not to advertise."}'::jsonb),
('spanish:3-1-school-life-and-subjects:learn:f8840dae', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'learn', 'mcq', 1, '{"readingTitle": "What subjects do I study? (las asignaturas)", "reading": "<p>School subjects are <span data-say=\"las asignaturas\">las asignaturas</span>. Most take a definite article, and some are plural. Tap 🔊 to hear each one.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"las matemáticas\">las matemáticas</span></td><td>maths</td><td><span data-say=\"la historia\">la historia</span></td><td>history</td></tr>\n              <tr><td><span data-say=\"la geografía\">la geografía</span></td><td>geography</td><td><span data-say=\"las ciencias\">las ciencias</span></td><td>science</td></tr>\n              <tr><td><span data-say=\"el inglés\">el inglés</span></td><td>English</td><td><span data-say=\"el español\">el español</span></td><td>Spanish</td></tr>\n              <tr><td><span data-say=\"la educación física\">la educación física</span></td><td>PE</td><td><span data-say=\"el dibujo\">el dibujo</span></td><td>art</td></tr>\n              <tr><td><span data-say=\"la música\">la música</span></td><td>music</td><td><span data-say=\"la informática\">la informática</span></td><td>ICT / computing</td></tr>\n              <tr><td><span data-say=\"la tecnología\">la tecnología</span></td><td>technology</td><td>&nbsp;</td><td>&nbsp;</td></tr>\n            </table>\n            <p>Model sentence: <span data-say=\"Estudio matemáticas, inglés y ciencias en el instituto.\">Estudio matemáticas, inglés y ciencias en el instituto.</span> — <em>I study maths, English and science at school.</em></p>", "question": "Which subject is ‘la informática’?", "options": ["ICT / computing", "religious education, taught weekly", "physical education outdoors", "modern foreign languages generally"]}'::jsonb, '{"answer": 0, "explain": "la informática = ICT / computing. The traps swap in other named subjects that sound plausible."}'::jsonb),
('spanish:3-1-school-life-and-subjects:learn:596e9df3', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'learn', 'mcq', 1, '{"readingTitle": "How do I give an opinion on a subject?", "reading": "<p><span data-say=\"me gusta\">me gusta</span> (I like) agrees with a singular subject; <span data-say=\"me gustan\">me gustan</span> agrees with a plural subject like <span data-say=\"las matemáticas\">las matemáticas</span> or <span data-say=\"las ciencias\">las ciencias</span> — exactly like ‘gustar’ works elsewhere.</p>\n            <ul>\n              <li><span data-say=\"Me gusta el español porque es interesante.\">Me gusta el español porque es interesante.</span> (I like Spanish because it’s interesting.)</li>\n              <li><span data-say=\"Me gustan las ciencias porque son útiles.\">Me gustan las ciencias porque son útiles.</span> (I like science because it’s useful.)</li>\n            </ul>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"mi asignatura preferida es\">mi asignatura preferida es</span></td><td>my favourite subject is</td></tr>\n              <tr><td><span data-say=\"se me da bien\">se me da bien</span></td><td>I am good at (it)</td></tr>\n              <tr><td><span data-say=\"se me da mal\">se me da mal</span></td><td>I am bad at (it)</td></tr>\n              <tr><td><span data-say=\"es útil\">es útil</span> / <span data-say=\"es aburrido\">es aburrido</span></td><td>it’s useful / it’s boring</td></tr>\n            </table>", "question": "Why is it ‘me gustan las ciencias’ and not ‘me gusta las ciencias’?", "options": ["‘las ciencias’ is plural, so the verb is plural", "‘ciencias’ is one of the few masculine subject nouns", "it describes something that will happen in the future", "‘gustar’ never changes its form for any subject"]}'::jsonb, '{"answer": 0, "explain": "Like elsewhere, gustar agrees with what is liked; ‘las ciencias’ is plural → gustan."}'::jsonb),
('spanish:3-1-school-life-and-subjects:learn:05d308d9', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'learn', 'mcq', 1, '{"readingTitle": "How do I compare subjects?", "reading": "<p>Use <strong>más / menos + adjective + que</strong> to compare, and <span data-say=\"prefiero\">prefiero</span> (I prefer) to state a preference directly. The adjective agrees in number with the subject.</p>\n            <ul>\n              <li><span data-say=\"Las matemáticas son más difíciles que el dibujo.\">Las matemáticas son más difíciles que el dibujo.</span> (Maths is more difficult than art.)</li>\n              <li><span data-say=\"La educación física es menos aburrida que la historia.\">La educación física es menos aburrida que la historia.</span> <span class=\"tier-h\">H</span> (PE is less boring than history.)</li>\n              <li><span data-say=\"Prefiero la música a la tecnología porque soy creativo.\">Prefiero la música a la tecnología porque soy creativo.</span></li>\n            </ul>", "question": "What does ‘más difícil que’ mean?", "options": ["more difficult than", "less difficult than, in fact easier", "exactly as difficult as", "the single most difficult subject of all"]}'::jsonb, '{"answer": 0, "explain": "más + adjective + que = more … than. ‘menos … que’ would mean less; ‘tan … como’ would mean as … as."}'::jsonb),
('spanish:3-1-school-life-and-subjects:learn:82fc2bc3', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'learn', 'mcq', 1, '{"readingTitle": "What is my school like? (el instituto)", "reading": "<p>The school is <span data-say=\"el instituto\">el instituto</span>. Key places on site — tap 🔊 to hear each one:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el aula\">el aula</span></td><td>the classroom</td><td><span data-say=\"el laboratorio\">el laboratorio</span></td><td>the lab</td></tr>\n              <tr><td><span data-say=\"la biblioteca\">la biblioteca</span></td><td>the library</td><td><span data-say=\"el comedor\">el comedor</span></td><td>the canteen</td></tr>\n              <tr><td><span data-say=\"el patio\">el patio</span></td><td>the playground</td><td><span data-say=\"el gimnasio\">el gimnasio</span></td><td>the gym</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En mi instituto hay una biblioteca grande y dos laboratorios.\">En mi instituto hay una biblioteca grande y dos laboratorios.</span></p>", "question": "Which place is ‘el comedor’?", "options": ["the canteen", "the school library building", "an ordinary classroom", "the outdoor sports field"]}'::jsonb, '{"answer": 0, "explain": "el comedor = the canteen, where students eat lunch."}'::jsonb),
('spanish:3-1-school-life-and-subjects:learn:2b56fedd', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'learn', 'mcq', 1, '{"readingTitle": "What is a typical school day like?", "reading": "<p>Talking about your <span data-say=\"el horario\">el horario</span> (timetable) and school day:</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"empezar\">empezar</span></td><td>to start</td><td><span data-say=\"terminar\">terminar</span></td><td>to finish</td></tr>\n              <tr><td><span data-say=\"el recreo\">el recreo</span></td><td>break time</td><td><span data-say=\"los deberes\">los deberes</span></td><td>homework</td></tr>\n              <tr><td><span data-say=\"llevar uniforme\">llevar uniforme</span></td><td>to wear (a) uniform</td><td>&nbsp;</td><td>&nbsp;</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Las clases empiezan a las nueve y terminan a las tres y media.\">Las clases empiezan a las nueve y terminan a las tres y media.</span> — <em>Lessons start at nine and finish at half past three.</em></p>\n            <p>Also: <span data-say=\"Hago los deberes después de las clases.\">Hago los deberes después de las clases.</span></p>\n            <p>Instead of the bus or bike, some students prefer to <span data-say=\"ir andando\">ir andando</span> (to walk / go on foot): <span data-say=\"Prefiero ir andando al instituto porque vivo cerca.\">Prefiero ir andando al instituto porque vivo cerca.</span> — I prefer to walk to school because I live nearby.</p>", "question": "What does ‘los deberes’ mean?", "options": ["homework", "the printed weekly timetable", "morning break time", "the compulsory uniform"]}'::jsonb, '{"answer": 0, "explain": "los deberes = homework. A common false-friend trap is thinking it means ‘duties’."}'::jsonb),
('spanish:3-1-school-life-and-subjects:learn:00d0da52', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'learn', 'mcq', 1, '{"readingTitle": "Higher: teachers and school rules", "reading": "<p><span class=\"tier-h\">H</span> The teacher is <span data-say=\"el profesor\">el profesor</span> / <span data-say=\"la profesora\">la profesora</span>. School rules (<span data-say=\"las normas\">las normas</span>) use impersonal structures followed by an infinitive:</p>\n            <ul>\n              <li><span data-say=\"se debe llevar uniforme\">se debe llevar uniforme</span> — one must wear uniform</li>\n              <li><span data-say=\"no se debe usar el móvil\">no se debe usar el móvil</span> — one must not use a mobile phone</li>\n              <li><span data-say=\"está prohibido comer en clase\">está prohibido comer en clase</span> <span class=\"tier-h\">H</span> — it is forbidden to eat in class</li>\n              <li><strong>hay que</strong> + infinitive — you have to (do something), e.g. respect the teachers</li>\n            </ul>\n            <p>Example: <span data-say=\"En mi instituto está prohibido llevar joyas y hay que respetar a los profesores.\">En mi instituto está prohibido llevar joyas y hay que respetar a los profesores.</span></p>", "question": "What follows ‘está prohibido’, ‘se debe’ and ‘hay que’?", "options": ["an infinitive (comer, llevar, respetar…)", "a verb conjugated in the preterite past tense", "an adjective that must agree", "a plural noun used on its own"]}'::jsonb, '{"answer": 0, "explain": "All three rule structures are followed by an infinitive."}'::jsonb),
('spanish:3-1-school-life-and-subjects:learn:9abb1ec2', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'learn', 'mcq', 1, '{"readingTitle": "Who''s who at school? (people and friendships)", "reading": "<p>More people you''ll meet, plus how to talk about school friendships. <span data-say=\"el señor\">el señor</span> / <span data-say=\"la señora\">la señora</span> go before a surname, like Mr/Mrs — useful for addressing teachers politely.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el compañero\">el compañero</span> / <span data-say=\"la compañera\">la compañera</span></td><td>classmate</td><td><span data-say=\"la amistad\">la amistad</span></td><td>friendship</td></tr>\n              <tr><td><span data-say=\"el alumno\">el alumno</span> / <span data-say=\"la alumna\">la alumna</span></td><td>pupil</td><td><span data-say=\"el estudiante\">el estudiante</span> / <span data-say=\"la estudiante\">la estudiante</span></td><td>student</td></tr>\n              <tr><td><span data-say=\"la autoridad\">la autoridad</span></td><td>authority</td><td><span data-say=\"el edificio\">el edificio</span></td><td>building</td></tr>\n              <tr><td><span data-say=\"la escuela\">la escuela</span></td><td>school (often primary)</td><td><span data-say=\"enseñar\">enseñar</span></td><td>to teach</td></tr>\n            </table>\n            <p>Note: <span data-say=\"la escuela\">la escuela</span> usually means a primary school, while <span data-say=\"el instituto\">el instituto</span> is secondary school — you already know both!</p>\n            <p>Example: <span data-say=\"El señor García enseña historia y siempre respeta a los alumnos.\">El señor García enseña historia y siempre respeta a los alumnos.</span> — Mr García teaches history and always respects the pupils.</p>\n            <p>Also: <span data-say=\"Mi compañera de clase y yo tenemos una buena amistad.\">Mi compañera de clase y yo tenemos una buena amistad.</span> — My classmate and I have a good friendship. <span data-say=\"Mi hermano mayor también fue alumno en este edificio.\">Mi hermano mayor también fue alumno en este edificio.</span> — My older brother was also a pupil in this building.</p>\n            <p><span data-say=\"entender\">entender</span> (to understand) and the reflexive <span data-say=\"entenderse bien con\">entenderse bien con</span> (to get on well with) are a useful pair: <span data-say=\"No entiendo la pregunta, pero me entiendo muy bien con mi profesora.\">No entiendo la pregunta, pero me entiendo muy bien con mi profesora.</span> — I don''t understand the question, but I get on very well with my teacher.</p>", "question": "Which Spanish word usually means a primary school, unlike ‘el instituto’?", "options": ["la escuela", "el edificio nuevo del centro", "la autoridad del director", "el estudiante universitario"]}'::jsonb, '{"answer": 0, "explain": "la escuela usually refers to a primary school; el instituto is secondary school."}'::jsonb),
('spanish:3-1-school-life-and-subjects:learn:7233cfa0', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'learn', 'mcq', 1, '{"readingTitle": "School rules, behaviour and uniform", "reading": "<p>More classroom behaviour and rules — building on <span data-say=\"está prohibido\">está prohibido</span> and <span data-say=\"se debe\">se debe</span> from before.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"permitir\">permitir</span></td><td>to allow</td><td><span data-say=\"la regla\">la regla</span></td><td>the rule</td></tr>\n              <tr><td><span data-say=\"el silencio\">el silencio</span></td><td>silence</td><td><span data-say=\"callarse\">callarse</span></td><td>to be quiet</td></tr>\n              <tr><td><span data-say=\"gritar\">gritar</span></td><td>to shout</td><td><span data-say=\"castigar\">castigar</span></td><td>to punish</td></tr>\n              <tr><td><span data-say=\"estricto\">estricto</span></td><td>strict</td><td><span data-say=\"obligatorio\">obligatorio</span></td><td>compulsory</td></tr>\n              <tr><td><span data-say=\"el pantalón\">el pantalón</span></td><td>trousers</td><td><span data-say=\"la falda\">la falda</span></td><td>skirt</td></tr>\n              <tr><td><span data-say=\"entregar\">entregar</span></td><td>to hand in</td><td><span data-say=\"la culpa\">la culpa</span></td><td>blame, fault</td></tr>\n            </table>\n            <p>Example: <span data-say=\"En mi instituto no se permite gritar en el pasillo; hay que callarse y guardar silencio.\">En mi instituto no se permite gritar en el pasillo; hay que callarse y guardar silencio.</span></p>\n            <p>Uniform rule: <span data-say=\"El uniforme es obligatorio: los chicos llevan pantalón y las chicas pueden llevar falda.\">El uniforme es obligatorio: los chicos llevan pantalón y las chicas pueden llevar falda.</span></p>\n            <p>Homework rule: <span data-say=\"Hay que entregar los deberes a tiempo; si no, el profesor te castiga.\">Hay que entregar los deberes a tiempo; si no, el profesor te castiga.</span> Nadie quiere <span data-say=\"echar la culpa\">echar la culpa</span> (place the blame) a un compañero cuando algo va mal.</p>\n            <p><span class=\"tier-h\">H</span> Two serious problems schools must tackle: <span data-say=\"el acoso\">el acoso</span> (bullying) and <span data-say=\"amenazar\">amenazar</span> (to threaten) — e.g. <span data-say=\"Está muy mal amenazar o acosar a otro alumno.\">Está muy mal amenazar o acosar a otro alumno.</span></p>\n            <p><span class=\"tier-h\">H</span> Teachers sometimes <span data-say=\"advertir\">advertir</span> (to warn) students, and may say <span data-say=\"¡Basta!\">¡Basta!</span> (Enough!) or <span data-say=\"basta de\">basta de</span> + infinitive: <span data-say=\"El profesor advierte a los alumnos: ''¡Basta de gritar en el pasillo!''\">El profesor advierte a los alumnos: ''¡Basta de gritar en el pasillo!''</span> — The teacher warns the students: ''Enough shouting in the corridor!''</p>", "question": "What does ‘el acoso’ mean in a school context?", "options": ["bullying", "a compulsory school rule about uniform", "a strict but fair teacher", "permission to leave class early"]}'::jsonb, '{"answer": 0, "explain": "el acoso = bullying, a serious pastoral issue schools must tackle."}'::jsonb),
('spanish:3-1-school-life-and-subjects:learn:cdb217af', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'learn', 'mcq', 1, '{"readingTitle": "Succeeding — or struggling — in exams", "reading": "<p>Vocabulary for talking about how well (or badly) things go at school.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el sistema\">el sistema</span></td><td>system</td><td><span data-say=\"el resultado\">el resultado</span></td><td>result</td></tr>\n              <tr><td><span data-say=\"la prueba\">la prueba</span></td><td>test/proof</td><td><span data-say=\"el esfuerzo\">el esfuerzo</span></td><td>effort</td></tr>\n              <tr><td><span data-say=\"el conocimiento\">el conocimiento</span></td><td>knowledge</td><td><span data-say=\"la memoria\">la memoria</span></td><td>memory</td></tr>\n              <tr><td><span data-say=\"el apoyo\">el apoyo</span></td><td>support</td><td><span data-say=\"merecer\">merecer</span></td><td>to deserve</td></tr>\n              <tr><td><span data-say=\"superar\">superar</span></td><td>to pass/overcome</td><td><span data-say=\"suspender\">suspender</span></td><td>to fail (an exam)</td></tr>\n              <tr><td><span data-say=\"repasar\">repasar</span></td><td>to revise</td><td><span data-say=\"la suerte\">la suerte</span></td><td>luck</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Si repasas con esfuerzo, mereces un buen resultado; si no estudias, puedes suspender.\">Si repasas con esfuerzo, mereces un buen resultado; si no estudias, puedes suspender.</span> <span data-say=\"¡Buena suerte en el examen!\">¡Buena suerte en el examen!</span> — Good luck in the exam!</p>\n            <p>Student types: <span data-say=\"listo\">listo</span> (clever), <span data-say=\"tonto\">tonto</span> (silly), <span data-say=\"vago\">vago</span> / <span data-say=\"perezoso\">perezoso</span> (lazy) and <span data-say=\"la inteligencia\">la inteligencia</span> (intelligence).</p>\n            <p>Example: <span data-say=\"Mi compañero es muy listo y tiene mucha inteligencia, pero yo soy un poco vago.\">Mi compañero es muy listo y tiene mucha inteligencia, pero yo soy un poco vago.</span></p>\n            <p>Other useful verbs: <span data-say=\"comentar\">comentar</span> (to comment on) and <span data-say=\"preocuparse por\">preocuparse por</span> (to worry about): <span data-say=\"El profesor comenta mis deberes y me da consejos, así que no me preocupo por el examen.\">El profesor comenta mis deberes y me da consejos, así que no me preocupo por el examen.</span> — The teacher comments on my homework and gives me advice, so I don''t worry about the exam.</p>\n            <p><span class=\"tier-h\">H</span> Before the exam: <span data-say=\"he cubierto todo el temario\">he cubierto todo el temario</span> (I have covered the whole syllabus) — <span data-say=\"Ya he cubierto todo el temario, así que estoy preparado.\">Ya he cubierto todo el temario, así que estoy preparado.</span></p>", "question": "What does ‘suspender un examen’ mean?", "options": ["to fail an exam", "to pass an exam with a great result", "to revise thoroughly before an exam", "to deserve extra support in class"]}'::jsonb, '{"answer": 0, "explain": "suspender = to fail (an exam) — a common false-friend trap, since it looks like ‘suspend’."}'::jsonb),
('spanish:3-1-school-life-and-subjects:learn:b0f49bdd', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'learn', 'mcq', 1, '{"readingTitle": "More subjects, the school year and school life", "reading": "<p>A few more useful nouns and adjectives for describing subjects, dates and everyday school life.</p>\n            <table class=\"vocab-tbl\">\n              <tr><td><span data-say=\"el idioma\">el idioma</span></td><td>language</td><td><span data-say=\"el lenguaje\">el lenguaje</span></td><td>language/speech (general)</td></tr>\n              <tr><td><span data-say=\"el castellano\">el castellano</span></td><td>Castilian Spanish</td><td><span data-say=\"la opción\">la opción</span></td><td>option</td></tr>\n              <tr><td><span data-say=\"septiembre\">septiembre</span></td><td>September</td><td><span data-say=\"la economía\">la economía</span></td><td>economics</td></tr>\n              <tr><td><span data-say=\"la mochila\">la mochila</span></td><td>backpack</td><td><span data-say=\"el bolígrafo\">el bolígrafo</span></td><td>pen</td></tr>\n              <tr><td><span data-say=\"la página\">la página</span></td><td>page</td><td><span data-say=\"la lista\">la lista</span></td><td>list</td></tr>\n              <tr><td><span data-say=\"la excursión\">la excursión</span></td><td>school trip</td><td><span data-say=\"la orquesta\">la orquesta</span></td><td>orchestra</td></tr>\n              <tr><td><span data-say=\"el concurso\">el concurso</span></td><td>competition</td><td><span data-say=\"el estadio\">el estadio</span></td><td>stadium</td></tr>\n              <tr><td><span data-say=\"deportivo\">deportivo</span></td><td>sports (adj)</td><td><span data-say=\"la bicicleta\">la bicicleta</span>, <span data-say=\"la bici\">la bici</span></td><td>bicycle</td></tr>\n              <tr><td><span data-say=\"la recepción\">la recepción</span></td><td>reception</td><td><span data-say=\"la puerta\">la puerta</span></td><td>door</td></tr>\n              <tr><td><span data-say=\"la instalación\">la instalación</span></td><td>facility</td><td><span data-say=\"numeroso\">numeroso</span></td><td>numerous</td></tr>\n              <tr><td><span data-say=\"cerrado\">cerrado</span></td><td>closed</td><td><span data-say=\"instalar\">instalar</span></td><td>to install</td></tr>\n            </table>\n            <p>Example: <span data-say=\"Las clases empiezan en septiembre; escojo mis opciones para el próximo curso, como la economía o un segundo idioma.\">Las clases empiezan en septiembre; escojo mis opciones para el próximo curso, como la economía o un segundo idioma.</span></p>\n            <p>Also: <span data-say=\"Voy al instituto en bicicleta y guardo mis bolígrafos en la mochila.\">Voy al instituto en bicicleta y guardo mis bolígrafos en la mochila.</span> <span data-say=\"En clase de informática aprendemos a instalar programas nuevos.\">En clase de informática aprendemos a instalar programas nuevos.</span></p>\n            <p>Extras: <span data-say=\"Nuestra escuela tiene una orquesta y un equipo que gana concursos.\">Nuestra escuela tiene una orquesta y un equipo que gana concursos.</span> <span data-say=\"Cerca del estadio hay instalaciones deportivas numerosas.\">Cerca del estadio hay instalaciones deportivas numerosas.</span></p>\n            <p>On the last day of term there''s often an <span data-say=\"excursión\">excursión</span> (school trip) — <span data-say=\"¡Estoy muy emocionado por la excursión!\">¡Estoy muy emocionado por la excursión!</span> (I''m very excited about the trip!) <span data-say=\"Los visitantes esperan en la recepción, cerca de la puerta principal, que está cerrada fuera del horario escolar.\">Los visitantes esperan en la recepción, cerca de la puerta principal, que está cerrada fuera del horario escolar.</span></p>", "question": "When do Spanish school subjects and options for next year usually get chosen, according to this page?", "options": ["around September, when classes start", "only during the summer excursión", "on the very last day of the school year", "the moment you turn eighteen years old"]}'::jsonb, '{"answer": 0, "explain": "septiembre = September, when the school year (and choosing options) begins."}'::jsonb),
('spanish:3-1-school-life-and-subjects:misc:184073f5', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Me gusta las matemáticas.</p><p><strong>✅ The correct idea:</strong> Me gustan las matemáticas.</p>", "question": "Why is ‘Me gusta las matemáticas’ wrong?", "options": ["‘las matemáticas’ is plural, so it must be ‘gustan’", "‘matemáticas’ needs a written accent on the first syllable", "the pronoun should be ‘te’, not ‘me’", "‘gustar’ should never be used with school subjects"]}'::jsonb, '{"answer": 0, "explain": "gustar agrees with what is liked; a plural subject needs the plural verb form."}'::jsonb),
('spanish:3-1-school-life-and-subjects:misc:567abf88', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ‘El colegio’ significa ‘the college’ (una universidad).</p><p><strong>✅ The correct idea:</strong> ‘El colegio’ significa ‘the school’.</p>", "question": "What does ‘el colegio’ mean?", "options": ["a school", "a university college for adults", "a public library building", "an after-school sports club"]}'::jsonb, '{"answer": 0, "explain": "False friend! el colegio = a school (often primary), not an English ‘college’."}'::jsonb),
('spanish:3-1-school-life-and-subjects:misc:83fb9e5c', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ‘Asistir a clase’ significa ‘to assist in class’ (ayudar).</p><p><strong>✅ The correct idea:</strong> ‘Asistir a clase’ significa ‘to attend class’.</p>", "question": "What does ‘asistir a clase’ actually mean?", "options": ["to attend class", "to assist or help in class", "to skip class deliberately", "to teach a class"]}'::jsonb, '{"answer": 0, "explain": "False friend! asistir = to attend, not to assist. ‘Ayudar’ is the verb for ‘to help’."}'::jsonb),
('spanish:3-1-school-life-and-subjects:misc:b37adeec', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Se me da bien las matemáticas.</p><p><strong>✅ The correct idea:</strong> Se me dan bien las matemáticas.</p>", "question": "Why is it ‘se me dan bien’, not ‘se me da bien’, here?", "options": ["‘las matemáticas’ is plural, so ‘dar’ agrees as ‘dan’", "‘dar’ must always be written as ‘dan’, whatever the subject happens to be", "‘matemáticas’ is treated as a masculine noun here", "it is describing a completed past action, not now"]}'::jsonb, '{"answer": 0, "explain": "Just like gustar, ‘se me da/dan bien’ agrees with the subject: plural subject → dan."}'::jsonb),
('spanish:3-1-school-life-and-subjects:misc:89e379a3', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> El profesora es simpática.</p><p><strong>✅ The correct idea:</strong> La profesora es simpática.</p>", "question": "What is wrong with ‘El profesora es simpática’?", "options": ["the article should be feminine ‘la’, matching profesora", "‘profesora’ should always come before the article, not after it", "nothing at all — the sentence is already completely correct", "‘simpática’ should not end in a final letter ‘a’"]}'::jsonb, '{"answer": 0, "explain": "profesora is feminine, so it needs the feminine article ‘la’, not ‘el’."}'::jsonb),
('spanish:3-1-school-life-and-subjects:misc:42248175', 'spanish', 'spanish:3-1-school-life-and-subjects', '3.1 School Life and Subjects', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Soy listo ahora mismo, voy a clase.</p><p><strong>✅ The correct idea:</strong> Estoy listo ahora mismo, voy a clase.</p>", "question": "Why must this sentence use ‘estoy’, not ‘soy’, with ‘listo’ here?", "options": ["‘estar listo’ means ready (temporary); ‘ser listo’ means clever (a trait)", "‘listo’ can only ever be used together with the verb ‘ser’, in every single sentence", "‘listo’ must agree with a plural subject in this exact sentence, according to this rule", "‘ir a clase’ always requires the verb ‘estar’ beforehand, in absolutely every case"]}'::jsonb, '{"answer": 0, "explain": "ser listo = to be clever (a lasting trait); estar listo = to be ready (a temporary state) — a classic ser/estar contrast."}'::jsonb),
